B.MN=new A.at(B.iu,["natural",u.H,"Natural & Functional Medicine","6 Months","Intermediate","Limited Seats","Explore the principles of functional and integrative medicine, including nutrition therapy, herbal remedies, detoxification, and lifestyle modification strategies. Designed for healthcare practitioners seeking a holistic approach.",B.Js],t.yf)
B.K_=s(["Detox pathways & physiology","Therapeutic techniques","Diet & lifestyle guidance","Practical demonstrations","Certificate upon completion"],t.s)
B.MM=new A.at(B.iu,["bio",u.u,"Bio-Purification Therapy Training","6 Months","Beginner","Limited Seats","Master the methods of bio-purification and detoxification therapy. This training covers holistic detox principles, therapeutic protocols, and practical techniques used to cleanse and restore the body naturally.",B.K_],t.yf)
